1	<?php
2	namespace App\Domain\Reservations;
3	
4	use App\Domain\Availability\AvailabilityService;
5	use App\Models\{ReservationRequest, User, AuditLog, VenueTimeSlot};
6	use Illuminate\Support\Facades\DB;
7	use Illuminate\Support\Facades\Log;
8	
9	class ReservationService
10	{
11	    public function __construct(protected AvailabilityService $availability) {}
12	
13	    public function createReservation(User $user, array $data): ReservationRequest
14	    {
15	        return DB::transaction(function () use ($user, $data) {
16	            // Check allowlist/blacklist
17	            $resource = \App\Models\Resource::findOrFail($data['resource_id']);
18	            $accessCheck = $this->availability->checkUserResourceAccess($user, $resource);
19	            if (!$accessCheck['allowed']) {
20	                throw new \App\Common\Exceptions\BusinessRuleException($accessCheck['reason']);
21	            }
22	
23	            // Validate resource type matches reservation type
24	            if ($data['reservation_type'] === 'venue' && $resource->resource_type !== 'venue') {
25	                throw new \App\Common\Exceptions\BusinessRuleException('Venue reservations can only be made for venue resources.');
26	            }
27	            if ($data['reservation_type'] === 'equipment' && $resource->resource_type !== 'equipment') {
28	                throw new \App\Common\Exceptions\BusinessRuleException('Equipment reservations can only be made for equipment resources.');
29	            }
30	
31	            if ($data['reservation_type'] === 'venue') {
32	                // Verify the venue belongs to the claimed resource
33	                $venue = \App\Models\Venue::where('id', $data['venue_id'] ?? 0)
34	                    ->where('resource_id', $resource->id)
35	                    ->first();
36	
37	                if (!$venue) {
38	                    throw new \App\Common\Exceptions\BusinessRuleException('Venue does not belong to this resource.');
39	                }
40	
41	                $slot = VenueTimeSlot::where('id', $data['venue_time_slot_id'])
42	                    ->lockForUpdate()
43	                    ->firstOrFail();
44	
45	                if (!$slot->is_available) {
46	                    throw new \App\Common\Exceptions\BusinessRuleException('Time slot is not available.');
47	                }
48	
49	                if ($slot->reserved_by_reservation_id !== null) {
50	                    throw new \App\Common\Exceptions\BusinessRuleException(
51	                        'Time slot conflict: this slot is already reserved.'
52	                    );
53	                }
54	
55	                // Verify slot belongs to the validated venue
56	                if ($slot->venue_id !== $venue->id) {
57	                    throw new \App\Common\Exceptions\BusinessRuleException('Time slot does not belong to the requested venue.');
58	                }
59	
60	                // Derive dates from the slot
61	                $startDate = $slot->date;
62	                $endDate = $slot->date;
63	            } else {
64	                // Equipment reservation: check user limits
65	                $check = $this->availability->canUserBorrow($user);
66	                if (!$check['allowed']) {
67	                    throw new \App\Common\Exceptions\BusinessRuleException($check['reason']);
68	                }
69	                $startDate = $data['start_date'];
70	                $endDate = $data['end_date'];
71	
72	                // Check for overlapping equipment reservations
73	                if ($this->availability->checkEquipmentReservationOverlap(
74	                    $data['resource_id'], $data['start_date'], $data['end_date']
75	                )) {
76	                    throw new \App\Common\Exceptions\BusinessRuleException(
77	                        'Equipment reservation conflict: an existing reservation overlaps this date range.'
78	                    );
79	                }
80	            }
81	
82	            // Validate requester's claim to class/assignment
83	            $classId = $data['class_id'] ?? null;
84	            $assignmentId = $data['assignment_id'] ?? null;
85	            if ($classId) {
86	                $ok = $user->permissionScopes()->where(function ($q) use ($classId) {
87	                    $q->where('class_id', $classId)->orWhere('scope_type', 'full');
88	                })->exists();
89	                if (!$ok) {
90	                    $courseId = \App\Models\ClassModel::where('id', $classId)->value('course_id');
91	                    $ok = $courseId && $user->permissionScopes()->where('course_id', $courseId)->exists();
92	                }
93	                if (!$ok) {
94	                    throw new \App\Common\Exceptions\BusinessRuleException('You are not enrolled in the specified class.');
95	                }
96	            }
97	
98	            $reservation = ReservationRequest::create([
99	                'user_id' => $user->id,
100	                'resource_id' => $data['resource_id'],
101	                'venue_id' => $data['venue_id'] ?? null,
102	                'venue_time_slot_id' => $data['venue_time_slot_id'] ?? null,
103	                'reservation_type' => $data['reservation_type'],
104	                'status' => 'pending',
105	                'start_date' => $startDate,
106	                'end_date' => $endDate,
107	                'notes' => $data['notes'] ?? null,
108	                'idempotency_key' => $data['idempotency_key'],
109	                'class_id' => $classId,
110	                'assignment_id' => $assignmentId,
111	            ]);
112	
113	            // Mark the slot as occupied
114	            if ($data['reservation_type'] === 'venue') {
115	                $slot->update(['reserved_by_reservation_id' => $reservation->id]);
116	            }
117	
118	            AuditLog::create([
119	                'user_id' => $user->id,
120	                'action' => 'reservation_created',
121	                'auditable_type' => ReservationRequest::class,
122	                'auditable_id' => $reservation->id,
123	            ]);
124	
125	            return $reservation;
126	        });
127	    }
128	
129	    public function approveReservation(ReservationRequest $reservation, User $approver, string $status, ?string $reason = null): ReservationRequest
130	    {
131	        return DB::transaction(function () use ($reservation, $approver, $status, $reason) {
132	            $reservation = ReservationRequest::whereKey($reservation->id)->lockForUpdate()->firstOrFail();
133	
134	            if ($reservation->status !== 'pending') {
135	                throw new \App\Common\Exceptions\BusinessRuleException('Can only act on pending reservations.');
136	            }
137	
138	            if ($status === 'rejected' && $reservation->reservation_type === 'venue' && $reservation->venue_time_slot_id) {
139	                // Release the slot
140	                VenueTimeSlot::where('id', $reservation->venue_time_slot_id)
141	                    ->where('reserved_by_reservation_id', $reservation->id)
142	                    ->update(['reserved_by_reservation_id' => null]);
143	            }
144	
145	            $reservation->update(['status' => $status]);
146	
147	            $reservation->approval()->create([
148	                'approved_by' => $approver->id,
149	                'status' => $status,
150	                'reason' => $reason,
151	            ]);
152	
153	            AuditLog::create([
154	                'user_id' => $approver->id,
155	                'action' => "reservation_{$status}",
156	                'auditable_type' => ReservationRequest::class,
157	                'auditable_id' => $reservation->id,
158	            ]);
159	
160	            Log::channel('operations')->info("Reservation {$status}", [
161	                'reservation_id' => $reservation->id, 'approver_id' => $approver->id,
162	            ]);
163	
164	            return $reservation->fresh();
165	        });
166	    }
167	
168	    public function cancelReservation(ReservationRequest $reservation, User $user): ReservationRequest
169	    {
170	        return DB::transaction(function () use ($reservation, $user) {
171	            $reservation = ReservationRequest::whereKey($reservation->id)->lockForUpdate()->firstOrFail();
172	
173	            if (!in_array($reservation->status, ['pending', 'approved'])) {
174	                throw new \App\Common\Exceptions\BusinessRuleException('Cannot cancel a reservation in this state.');
175	            }
176	
177	            // Release the venue time slot if applicable
178	            if ($reservation->reservation_type === 'venue' && $reservation->venue_time_slot_id) {
179	                VenueTimeSlot::where('id', $reservation->venue_time_slot_id)
180	                    ->where('reserved_by_reservation_id', $reservation->id)
181	                    ->update(['reserved_by_reservation_id' => null]);
182	            }
183	
184	            $reservation->update(['status' => 'cancelled']);
185	
186	            AuditLog::create([
187	                'user_id' => $user->id,
188	                'action' => 'reservation_cancelled',
189	                'auditable_type' => ReservationRequest::class,
190	                'auditable_id' => $reservation->id,
191	            ]);
192	
193	            return $reservation->fresh();
194	        });
195	    }
196	}
