2	
3	namespace App\Policies;
4	
5	use App\Models\{User, ReservationRequest, ClassModel};
6	
7	class ReservationRequestPolicy
8	{
9	    public function view(User $user, ReservationRequest $reservation): bool
10	    {
11	        if ($user->id === $reservation->user_id) return true;
12	        if ($user->isAdmin()) return true;
13	        if (!$user->isTeacher() && !$user->isTA()) return false;
14	        return $this->hasMatchingScope($user, $reservation);
15	    }
16	
17	    public function approve(User $user, ReservationRequest $reservation): bool
18	    {
19	        if ($user->isAdmin()) return true;
20	        if (!$user->isTeacher() && !$user->isTA()) return false;
21	        return $this->hasMatchingScope($user, $reservation);
22	    }
23	
24	    public function cancel(User $user, ReservationRequest $reservation): bool
25	    {
26	        if ($user->id === $reservation->user_id) return true;
27	        return $user->isAdmin();
28	    }
29	
30	    protected function hasMatchingScope(User $user, ReservationRequest $reservation): bool
31	    {
32	        if ($user->permissionScopes()->where('scope_type', 'full')->exists()) {
33	            return true;
34	        }
35	        if ($reservation->class_id && $user->permissionScopes()->where('class_id', $reservation->class_id)->exists()) {
36	            return true;
37	        }
38	        if ($reservation->assignment_id && $user->permissionScopes()->where('assignment_id', $reservation->assignment_id)->exists()) {
39	            return true;
40	        }
41	        // Course-level scope
42	        if ($reservation->class_id) {
43	            $courseId = ClassModel::where('id', $reservation->class_id)->value('course_id');
44	            if ($courseId && $user->permissionScopes()->where('course_id', $courseId)->exists()) {
45	                return true;
46	            }
47	        }
48	        return false;
49	    }
50	}
