11	use App\Models\ManufacturerAlias;
12	use Illuminate\Http\Request;
13	
14	class DataQualityController extends Controller
15	{
16	    public function __construct(protected DataQualityService $dq) {}
17	
18	    public function import(Request $request)
19	    {
20	        $request->validate([
21	            'file' => 'nullable|file|mimes:csv,txt,json',
22	            'rows' => 'nullable|array',
23	            'rows.*.name' => 'nullable|string',
24	        ]);
25	
26	        $rows = $request->input('rows');
27	
28	        // If no rows provided, parse from uploaded file
29	        if (empty($rows) && $request->hasFile('file')) {
30	            $file = $request->file('file');
31	            $ext = strtolower($file->getClientOriginalExtension());
32	
33	            if ($ext === 'json') {
34	                $content = file_get_contents($file->getRealPath());
35	                $rows = json_decode($content, true);
36	                if (!is_array($rows)) {
37	                    return response()->json(['error' => 'Invalid JSON: expected an array of objects.'], 422);
38	                }
39	            } elseif (in_array($ext, ['csv', 'txt'])) {
40	                $rows = [];
41	                $handle = fopen($file->getRealPath(), 'r');
42	                $headers = fgetcsv($handle);
43	                if (!$headers) {
44	                    fclose($handle);
45	                    return response()->json(['error' => 'CSV file is empty or has no header row.'], 422);
46	                }
47	                $headers = array_map('trim', $headers);
48	                while (($line = fgetcsv($handle)) !== false) {
49	                    if (count($line) === count($headers)) {
50	                        $rows[] = array_combine($headers, array_map('trim', $line));
51	                    }
52	                }
53	                fclose($handle);
54	            }
55	        }
56	
57	        if (empty($rows)) {
58	            return response()->json(['error' => 'No data provided. Upload a file or provide rows.'], 422);
59	        }
60	
61	        $batch = $this->dq->createImportBatch(
62	            $request->user(),
63	            $request->file?->getClientOriginalName() ?? 'inline',
64	            $rows
65	        );
66	
67	        return response()->json($this->dq->generateValidationReport($batch));
68	    }
69	
70	    public function batches()
71	    {
72	        return response()->json(ImportBatch::latest()->paginate(20));
73	    }
74	
75	    public function batchReport(ImportBatch $batch)
