80	    public function downloadReport(ImportBatch $batch)
81	    {
82	        $report = $this->dq->generateValidationReport($batch);
83	        $content = json_encode($report, JSON_PRETTY_PRINT);
84	        return response($content)->header('Content-Type', 'application/json')
85	            ->header('Content-Disposition', "attachment; filename=validation_report_{$batch->id}.json");
86	    }
87	
88	    public function remediationQueue()
89	    {
90	        $items = ImportValidationResult::whereIn('status', ['invalid', 'duplicate'])
91	            ->with('batch')
92	            ->latest()
93	            ->paginate(20);
94	
95	        // Shape response to match frontend expectations
96	        $items->getCollection()->transform(function ($item) {
97	            $errors = $item->validation_errors ?? [];
98	            return [
99	                'id' => $item->id,
100	                'severity' => $item->is_duplicate ? 'medium' : 'high',
101	                'type' => $item->is_duplicate ? 'duplicate' : 'validation',
102	                'title' => $item->original_data['name'] ?? "Row #{$item->row_number}",
103	                'description' => is_array($errors) ? implode('; ', $errors) : ($errors ?? 'Duplicate detected'),
104	                'affected_resource' => $item->duplicate_of_id ? ['name' => "Resource #{$item->duplicate_of_id}"] : null,
105	                'auto_fixable' => $item->status === 'invalid' && !empty($errors),
106	                'status' => $item->status,
107	                'batch_id' => $item->batch_id,
108	                'row_number' => $item->row_number,
109	                'original_data' => $item->original_data,
110	            ];
111	        });
112	
113	        return response()->json($items);
114	    }
115	
116	    public function remediateItem(Request $request, ImportValidationResult $item)
117	    {
118	        $request->validate(['action' => 'required|in:remediate,skip']);
119	        $item->update([
120	            'status' => $request->action === 'remediate' ? 'remediated' : 'skipped',
121	            'remediated_by' => $request->user()->id,
122	            'remediated_at' => now(),
123	        ]);
124	        return response()->json(['message' => 'Item updated.']);
125	    }
126	
127	    public function duplicates()
128	    {
129	        $candidates = DuplicateCandidate::where('status', 'pending')
130	            ->with(['resourceA'])
131	            ->paginate(20);
132	
133	        // Shape response to match frontend expectations
134	        $candidates->getCollection()->transform(function ($candidate) {
135	            $records = [];
136	            if ($candidate->resourceA) {
137	                $records[] = [
138	                    'id' => $candidate->resourceA->id,
139	                    'name' => $candidate->resourceA->name,
140	                    'type' => $candidate->resourceA->resource_type,
141	                    'department' => $candidate->resourceA->department?->name ?? 'Unknown',
142	                ];
143	            }
144	            // Include the imported row data for comparison
145	            $importedRow = null;
146	            if ($candidate->batch_id) {
147	                // Find the specific imported row that triggered this duplicate candidate
148	                // by matching the resource name similarity
149	                $candidateName = $candidate->resourceA?->name;
150	                $results = ImportValidationResult::where('batch_id', $candidate->batch_id)
151	                    ->whereIn('status', ['duplicate', 'valid'])
152	                    ->get();
153	                foreach ($results as $result) {
154	                    $rowName = $result->original_data['name'] ?? '';
155	                    if ($candidateName && $rowName) {
156	                        similar_text(strtolower($rowName), strtolower($candidateName), $pct);
157	                        if ($pct >= 80.0) {
158	                            $importedRow = $result->original_data;
159	                            break;
160	                        }
161	                    }
162	                }
163	                // Fallback: use first result if no similarity match found
164	                if (!$importedRow && $results->isNotEmpty()) {
165	                    $importedRow = $results->first()->original_data;
166	                }
167	            }
168	
169	            return [
170	                'id' => $candidate->id,
171	                'confidence' => $candidate->match_score / 100,
172	                'match_type' => $candidate->match_type,
173	                'records' => $records,
174	                'imported_row' => $importedRow,
175	                'status' => $candidate->status,
176	            ];
177	        });
178	
179	        return response()->json($candidates);
180	    }
181	
182	    public function resolveDuplicate(Request $request, DuplicateCandidate $candidate)
183	    {
184	        $request->validate(['action' => 'required|in:confirmed,dismissed']);
185	        $candidate->update(['status' => $request->action, 'reviewed_by' => $request->user()->id]);
186	        return response()->json(['message' => 'Resolved.']);
187	    }
188	
189	    public function stats()
190	    {
191	        $totalRecords = Resource::count();
192	        $withIssues = ImportValidationResult::whereIn('status', ['invalid', 'duplicate'])->count();
193	        $duplicateCandidates = DuplicateCandidate::where('status', 'pending')->count();
194	
195	        // Field completeness: compute percentage of non-null values for key resource fields
196	        $fields = ['description', 'category', 'vendor', 'manufacturer', 'model_number'];
197	        $fieldStats = [];
198	        foreach ($fields as $field) {
199	            if ($totalRecords > 0) {
200	                $filled = Resource::whereNotNull($field)->where($field, '!=', '')->count();
201	                $fieldStats[$field] = (int) round(($filled / $totalRecords) * 100);
202	            } else {
203	                $fieldStats[$field] = 0;
204	            }
205	        }
206	
207	        $completeness = $totalRecords > 0
208	            ? (int) round((array_sum($fieldStats) / (count($fields) * 100)) * 100)
209	            : 0;
210	
211	        return response()->json([
212	            'total_records' => $totalRecords,
213	            'records_with_issues' => $withIssues,
214	            'duplicate_candidates' => $duplicateCandidates,
215	            'completeness_pct' => $completeness,
216	            'field_stats' => $fieldStats,
217	        ]);
218	    }
219	
