1	<?php
2	namespace App\Domain\DataQuality;
3	
4	use App\Models\{ImportBatch, ImportValidationResult, DuplicateCandidate, Resource, TaxonomyTerm, ProhibitedTerm, VendorAlias, ManufacturerAlias, User};
5	use Illuminate\Support\Facades\DB;
6	use Illuminate\Support\Str;
7	
8	class DataQualityService
9	{
10	    public function createImportBatch(User $user, string $filename, array $rows): ImportBatch
11	    {
12	        return DB::transaction(function () use ($user, $filename, $rows) {
13	            $batch = ImportBatch::create([
14	                'imported_by' => $user->id,
15	                'filename' => $filename,
16	                'total_rows' => count($rows),
17	                'status' => 'processing',
18	                'started_at' => now(),
19	            ]);
20	
21	            $valid = 0;
22	            $invalid = 0;
23	            $duplicates = 0;
24	
25	            foreach ($rows as $index => $row) {
26	                $errors = $this->validateRow($row);
27	                $isDuplicate = $this->checkDuplicate($row, $batch->id, $index + 1);
28	
29	                // Check if THIS row has a near-duplicate by re-checking similarity directly
30	                // (checkDuplicate already created DuplicateCandidate records for near matches)
31	                $hasNearDuplicate = false;
32	                if (!$isDuplicate && !empty($row['name'])) {
33	                    $allResources = Resource::all();
34	                    foreach ($allResources as $existingRes) {
35	                        similar_text(Str::lower($row['name']), Str::lower($existingRes->name), $pct);
36	                        if ($pct >= 80.0) {
37	                            $hasNearDuplicate = true;
38	                            break;
39	                        }
40	                    }
41	                }
42	
43	                $status = 'valid';
44	                if (!empty($errors)) {
45	                    $status = 'invalid';
46	                    $invalid++;
47	                } elseif ($isDuplicate) {
48	                    $status = 'duplicate';
49	                    $duplicates++;
50	                } elseif ($hasNearDuplicate) {
51	                    $status = 'duplicate';
52	                    $duplicates++;
53	                } else {
54	                    $valid++;
55	                }
56	
57	                // Apply normalization to the stored data
58	                $normalizedData = $row;
59	                if (!empty($row['vendor'])) {
60	                    $normalizedData['vendor_normalized'] = $this->normalizeVendor($row['vendor']);
61	                }
62	                if (!empty($row['manufacturer'])) {
63	                    $normalizedData['manufacturer_normalized'] = $this->normalizeManufacturer($row['manufacturer']);
64	                }
65	
66	                ImportValidationResult::create([
67	                    'batch_id' => $batch->id,
68	                    'row_number' => $index + 1,
69	                    'original_data' => $normalizedData,
70	                    'validation_errors' => !empty($errors) ? $errors : null,
71	                    'is_duplicate' => $isDuplicate !== false,
72	                    'duplicate_of_id' => is_int($isDuplicate) ? $isDuplicate : null,
73	                    'status' => $status,
74	                ]);
75	            }
76	
77	            $batch->update([
78	                'processed_rows' => count($rows),
79	                'valid_rows' => $valid,
80	                'invalid_rows' => $invalid,
81	                'duplicate_rows' => $duplicates,
82	                'status' => 'completed',
83	                'completed_at' => now(),
84	            ]);
85	
86	            // Persist valid rows as new resources
87	            $validResults = ImportValidationResult::where('batch_id', $batch->id)
88	                ->where('status', 'valid')
89	                ->get();
90	
91	            $defaultDept = \App\Models\Department::first()
92	                ?? \App\Models\Department::create(['name' => 'Default', 'code' => 'DEF', 'description' => 'Default import department']);
93	
94	            foreach ($validResults as $result) {
95	                $rowData = $result->original_data;
96	                if (!empty($rowData['name'])) {
97	                    // Use department from import data if provided and valid, else default
98	                    $dept = $defaultDept;
99	                    if (!empty($rowData['department_code'])) {
100	                        $mappedDept = \App\Models\Department::where('code', $rowData['department_code'])->first();
101	                        if ($mappedDept) $dept = $mappedDept;
102	                    } elseif (!empty($rowData['department_id'])) {
103	                        $mappedDept = \App\Models\Department::find($rowData['department_id']);
104	                        if ($mappedDept) $dept = $mappedDept;
105	                    }
106	                    Resource::create([
107	                        'name' => $rowData['name'],
108	                        'description' => $rowData['description'] ?? null,
109	                        'resource_type' => $rowData['resource_type'] ?? 'equipment',
110	                        'category' => $rowData['category'] ?? 'Uncategorized',
111	                        'subcategory' => $rowData['subcategory'] ?? null,
112	                        'department_id' => $dept?->id,
113	                        'vendor' => $rowData['vendor_normalized'] ?? $rowData['vendor'] ?? null,
114	                        'manufacturer' => $rowData['manufacturer_normalized'] ?? $rowData['manufacturer'] ?? null,
115	                        'model_number' => $rowData['model_number'] ?? null,
116	                        'status' => 'active',
117	                        'tags' => isset($rowData['tags']) ? (is_array($rowData['tags']) ? $rowData['tags'] : explode(',', $rowData['tags'])) : null,
118	                    ]);
119	                }
120	            }
121	
122	            return $batch->fresh();
123	        });
124	    }
