126	    public function validateRow(array $row): array
127	    {
128	        $errors = [];
129	
130	        // Required fields
131	        if (empty($row['name'])) {
132	            $errors[] = 'Name is required.';
133	        }
134	
135	        // Prohibited terms check
136	        if (!empty($row['name'])) {
137	            $prohibited = $this->checkProhibitedTerms($row['name']);
138	            foreach ($prohibited as $term) {
139	                $errors[] = "Prohibited term found in name: '{$term}'";
140	            }
141	        }
142	
143	        if (!empty($row['notes'])) {
144	            $prohibited = $this->checkProhibitedTerms($row['notes']);
145	            foreach ($prohibited as $term) {
146	                $errors[] = "Prohibited term found in notes: '{$term}'";
147	            }
148	        }
149	
150	        // Taxonomy validation
151	        if (!empty($row['tags'])) {
152	            $tags = is_array($row['tags']) ? $row['tags'] : explode(',', $row['tags']);
153	            foreach ($tags as $tag) {
154	                $tag = trim($tag);
155	                if (!TaxonomyTerm::where('type', 'tag')->where('value', $tag)->where('is_active', true)->exists()) {
156	                    $errors[] = "Invalid tag: '{$tag}' not in controlled taxonomy.";
157	                }
158	            }
159	        }
160	
161	        // Category taxonomy validation
162	        if (!empty($row['category'])) {
163	            if (!TaxonomyTerm::where('type', 'category')->where('value', $row['category'])->where('is_active', true)->exists()) {
164	                $errors[] = "Invalid category: '{$row['category']}' not in controlled taxonomy.";
165	            }
166	        }
167	
168	        return $errors;
169	    }
170	
171	    public function checkProhibitedTerms(string $text): array
172	    {
173	        $found = [];
174	        $terms = ProhibitedTerm::where('severity', 'block')->pluck('term');
175	        $lowerText = Str::lower($text);
176	
177	        foreach ($terms as $term) {
178	            if (Str::contains($lowerText, Str::lower($term))) {
179	                $found[] = $term;
180	            }
181	        }
182	
183	        return $found;
184	    }
185	
186	    public function checkDuplicate(array $row, ?int $batchId = null, ?int $rowNumber = null): int|false
187	    {
188	        if (empty($row['name'])) {
189	            return false;
190	        }
191	
192	        $normalized = $this->normalizeTitle($row['name']);
193	
194	        // Exact match (normalized)
195	        $exact = Resource::whereRaw('LOWER(REPLACE(name, " ", "")) = ?', [$normalized])->first();
196	        if ($exact) {
197	            if ($batchId) {
198	                DuplicateCandidate::create([
199	                    'resource_a_id' => $exact->id,
200	                    'batch_id' => $batchId,
201	                    'match_type' => 'exact',
202	                    'match_score' => 100.00,
203	                    'status' => 'pending',
204	                ]);
205	            }
206	            return $exact->id;
207	        }
208	
209	        // Near match: check existing resources for high similarity (>= 80%)
210	        $candidates = Resource::all();
211	        foreach ($candidates as $candidate) {
212	            similar_text(Str::lower($row['name']), Str::lower($candidate->name), $percent);
213	            if ($percent >= 80.0) {
214	                if ($batchId) {
215	                    DuplicateCandidate::create([
216	                        'resource_a_id' => $candidate->id,
217	                        'batch_id' => $batchId,
218	                        'match_type' => 'near',
219	                        'match_score' => round($percent, 2),
220	                        'status' => 'pending',
221	                    ]);
222	                }
223	                // Near matches are flagged for review, not hard-blocked
224	                // Return false so the row isn't marked as 'duplicate' (it goes to remediation instead)
225	            }
226	        }
227	
228	        return false;
229	    }
