236	    public function normalizeVendor(string $vendor): string
237	    {
238	        $alias = VendorAlias::where('alias', $vendor)->where('status', 'approved')->first();
239	        return $alias ? $alias->canonical_name : $vendor;
240	    }
241	
242	    public function normalizeManufacturer(string $manufacturer): string
243	    {
244	        $alias = ManufacturerAlias::where('alias', $manufacturer)->where('status', 'approved')->first();
245	        return $alias ? $alias->canonical_name : $manufacturer;
246	    }
