248	    public function generateValidationReport(ImportBatch $batch): array
249	    {
250	        $results = ImportValidationResult::where('batch_id', $batch->id)->get();
251	
252	        return [
253	            'batch_id' => $batch->id,
254	            'filename' => $batch->filename,
255	            'summary' => [
256	                'total_rows' => $batch->total_rows,
257	                'valid' => $batch->valid_rows,
258	                'invalid' => $batch->invalid_rows,
259	                'duplicates' => $batch->duplicate_rows,
