22	    public function assignScope(Request $request)
23	    {
24	        $rules = [
25	            'user_id' => 'required|exists:users,id',
26	            'scope_type' => 'required|in:full,course,class,assignment,department',
27	        ];
28	
29	        // Enforce that scope_type matches exactly one required foreign key
30	        $type = $request->input('scope_type');
31	        if ($type === 'course') {
32	            $rules['course_id'] = 'required|exists:courses,id';
33	        } elseif ($type === 'class') {
34	            $rules['class_id'] = 'required|exists:classes,id';
35	        } elseif ($type === 'assignment') {
36	            $rules['assignment_id'] = 'required|exists:assignments,id';
37	        } elseif ($type === 'department') {
38	            $rules['department_id'] = 'required|exists:departments,id';
39	        }
40	        // 'full' requires no foreign key
41	
42	        $request->validate($rules);
43	
44	        // Strip foreign keys that don't match the scope_type to prevent mixed states
45	        $scopeData = [
46	            'scope_type' => $type,
47	            'course_id' => $type === 'course' ? $request->course_id : null,
48	            'class_id' => $type === 'class' ? $request->class_id : null,
49	            'assignment_id' => $type === 'assignment' ? $request->assignment_id : null,
50	            'department_id' => $type === 'department' ? $request->department_id : null,
51	        ];
52	
53	        $user = User::findOrFail($request->user_id);
