196	            $modelClass = self::REVEALABLE_MODELS[$modelKey];
197	        } else {
198	            $shortKey = array_search($modelKey, self::REVEALABLE_MODELS, true);
199	            $modelClass = $shortKey !== false ? $modelKey : null;
200	        }
201	
202	        if (!$modelClass) {
203	            return response()->json(['error' => 'Model type is not revealable.'], 422);
204	        }
205	        $allowedFields = self::REVEALABLE_FIELDS[$shortKey] ?? [];
206	        $requestedFields = array_intersect($request->fields, $allowedFields);
207	
208	        if (empty($requestedFields)) {
209	            return response()->json(['error' => 'None of the requested fields are revealable.'], 422);
210	        }
211	
212	        $record = $modelClass::find($request->model_id);
213	        if (!$record) {
214	            return response()->json(['error' => 'Record not found.'], 404);
215	        }
216	
217	        // Scope check: admin must have a permission scope that covers this record.
218	        // For User reveals: the admin needs full scope, or a scope whose course/class
219	        // intersects with the target user's enrollments (permission scopes).
220	        $admin = $request->user();
221	        $hasFullScope = $admin->permissionScopes()->where('scope_type', 'full')->exists();
222	        if (!$hasFullScope) {
223	            if ($modelClass === \App\Models\User::class) {
224	                // Check if target user shares any scoped course/class with this admin
225	                $adminClassIds = $admin->permissionScopes()->whereNotNull('class_id')->pluck('class_id');
226	                $adminCourseIds = $admin->permissionScopes()->whereNotNull('course_id')->pluck('course_id');
227	                $targetClassIds = $record->permissionScopes()->whereNotNull('class_id')->pluck('class_id');
228	                $targetCourseIds = $record->permissionScopes()->whereNotNull('course_id')->pluck('course_id');
229	
230	                $hasOverlap = $adminClassIds->intersect($targetClassIds)->isNotEmpty()
231	                    || $adminCourseIds->intersect($targetCourseIds)->isNotEmpty();
232	
233	                if (!$hasOverlap) {
234	                    return response()->json(['error' => 'You do not have scope to reveal this record.'], 403);
235	                }
236	            }
237	        }
238	
239	        $this->scopeService->revealSensitiveField(
240	            $admin, $modelClass, $request->model_id, $requestedFields, $request->reason
241	        );
242	
243	        $data = [];
244	        foreach ($requestedFields as $field) {
245	            $data[$field] = $record->$field ?? null;
246	        }
247	
248	        return response()->json(['revealed' => $data]);
249	    }
