14	class AvailabilityService
15	{
16	    const DEFAULT_MAX_ACTIVE_ITEMS = 2;
17	    const DEFAULT_LOAN_DAYS = 7;
18	    const DEFAULT_MAX_RENEWALS = 1;
19	
20	    public function getAvailableQuantity(Resource $resource): int
21	    {
22	        return $resource->inventoryLots->sum(function (InventoryLot $lot) {
23	            return $this->getLotAvailableQuantity($lot);
24	        });
25	    }
26	
27	    public function getLotAvailableQuantity(InventoryLot $lot): int
28	    {
29	        $total = $lot->serviceable_quantity;
30	
31	        // Active checkouts (not returned)
32	        $checkedOut = Checkout::where('inventory_lot_id', $lot->id)
33	            ->whereNull('returned_at')
34	            ->sum('quantity');
35	
36	        // Approved pending loan requests
37	        $approvedLoans = LoanRequest::where('inventory_lot_id', $lot->id)
38	            ->where('status', 'approved')
39	            ->sum('quantity');
40	
41	        // Pending/approved equipment reservations overlapping with the present
42	        $approvedReservations = ReservationRequest::where('resource_id', $lot->resource_id)
43	            ->where('reservation_type', 'equipment')
44	            ->whereIn('status', ['pending', 'approved'])
45	            ->where('start_date', '<=', now())
46	            ->where('end_date', '>=', now())
47	            ->count();
48	
49	        // In-transit and source-held transfers (sum quantity from transfer_requests)
50	        $inTransit = \App\Models\TransferRequest::where('inventory_lot_id', $lot->id)
51	            ->whereIn('status', ['pending', 'approved', 'in_transit'])
52	            ->sum('quantity');
53	
54	        return max(0, $total - $checkedOut - $approvedLoans - $approvedReservations - $inTransit);
55	    }
56	
57	    public function getUserActiveItemCount(User $user): int
58	    {
59	        $activeCheckouts = Checkout::where('checked_out_to', $user->id)
60	            ->whereNull('returned_at')
61	            ->sum('quantity');
62	
63	        $approvedRequests = LoanRequest::where('user_id', $user->id)
64	            ->where('status', 'approved')
65	            ->sum('quantity');
66	
67	        return $activeCheckouts + $approvedRequests;
68	    }
69	
70	    public function canUserBorrow(User $user, int $requestedQuantity = 1): array
71	    {
72	        $maxItems = $this->getMaxActiveItems($user);
73	        $currentCount = $this->getUserActiveItemCount($user);
74	        $remaining = $maxItems - $currentCount;
75	
76	        if ($remaining < $requestedQuantity) {
77	            return [
78	                'allowed' => false,
79	                'reason' => "Active item limit reached. Current: {$currentCount}, Max: {$maxItems}, Requested: {$requestedQuantity}",
80	                'current_count' => $currentCount,
81	                'max_items' => $maxItems,
82	            ];
83	        }
84	
85	        return ['allowed' => true, 'current_count' => $currentCount, 'max_items' => $maxItems];
86	    }
87	
88	    public function isTimeSlotAvailable(int $slotId): bool
89	    {
90	        $slot = VenueTimeSlot::find($slotId);
91	        if (!$slot) return false;
92	        return $slot->is_available && $slot->reserved_by_reservation_id === null;
93	    }
94	
95	    public function getMaxActiveItems(User $user): int
96	    {
97	        if ($user->membership && $user->membership->tier) {
98	            return $user->membership->tier->max_active_loans;
99	        }
100	        return self::DEFAULT_MAX_ACTIVE_ITEMS;
101	    }
102	
103	    public function getMaxLoanDays(User $user): int
104	    {
105	        if ($user->membership && $user->membership->tier) {
106	            return $user->membership->tier->max_loan_days;
107	        }
108	        return self::DEFAULT_LOAN_DAYS;
109	    }
110	
111	    public function canRenew(Checkout $checkout): array
112	    {
113	        $maxRenewals = self::DEFAULT_MAX_RENEWALS;
114	        if ($checkout->checkedOutTo->membership?->tier) {
115	            $maxRenewals = $checkout->checkedOutTo->membership->tier->max_renewals;
116	        }
117	
118	        if ($checkout->renewals()->count() >= $maxRenewals) {
119	            return ['allowed' => false, 'reason' => 'Maximum renewals reached.'];
120	        }
121	
122	        // Check waitlist
123	        $hasWaitlist = \App\Models\Waitlist::where('resource_id', $checkout->loanRequest->resource_id)
124	            ->whereNull('fulfilled_at')
125	            ->whereNull('expired_at')
126	            ->exists();
127	
128	        if ($hasWaitlist) {
129	            return ['allowed' => false, 'reason' => 'Cannot renew while others are waiting.'];
130	        }
131	
132	        return ['allowed' => true];
133	    }
134	
135	    /**
136	     * Check whether adding one more equipment reservation for the given date range
137	     * would exceed the resource's available inventory. Returns true if there IS a conflict.
138	     *
139	     * Each reservation consumes 1 unit. Available = total serviceable across all lots
140	     * minus active checkouts minus approved loans minus overlapping reservations minus transfers.
141	     */
142	    public function checkEquipmentReservationOverlap(int $resourceId, string $startDate, string $endDate, ?int $excludeId = null): bool
143	    {
144	        $resource = Resource::with('inventoryLots')->find($resourceId);
145	        if (!$resource) return true;
146	
147	        // Total serviceable across all lots
148	        $totalServiceable = $resource->inventoryLots->sum('serviceable_quantity');
149	
150	        // Active checkouts (not returned) for any lot of this resource
151	        $lotIds = $resource->inventoryLots->pluck('id');
152	        $checkedOut = Checkout::whereIn('inventory_lot_id', $lotIds)
153	            ->whereNull('returned_at')
154	            ->sum('quantity');
155	
156	        // Approved loan requests
157	        $approvedLoans = LoanRequest::whereIn('inventory_lot_id', $lotIds)
158	            ->where('status', 'approved')
159	            ->sum('quantity');
160	
161	        // Pending/in-transit transfers
162	        $inTransfer = \App\Models\TransferRequest::whereIn('inventory_lot_id', $lotIds)
163	            ->whereIn('status', ['pending', 'approved', 'in_transit'])
164	            ->sum('quantity');
165	
166	        // Count overlapping equipment reservations (each = 1 unit)
167	        $overlappingQuery = ReservationRequest::where('resource_id', $resourceId)
168	            ->where('reservation_type', 'equipment')
169	            ->whereIn('status', ['pending', 'approved'])
170	            ->where('start_date', '<=', $endDate)
171	            ->where('end_date', '>=', $startDate);
172	
173	        if ($excludeId) {
174	            $overlappingQuery->where('id', '!=', $excludeId);
175	        }
176	
177	        $overlappingCount = $overlappingQuery->count();
178	
179	        // Available for this date range = total - committed - already overlapping reservations
180	        $availableForRange = $totalServiceable - $checkedOut - $approvedLoans - $inTransfer - $overlappingCount;
181	
182	        // Conflict if adding 1 more reservation would exceed available
183	        return $availableForRange < 1;
184	    }
185	
186	    public function checkUserResourceAccess(User $user, Resource $resource): array
187	    {
188	        // Check if user is blacklisted for this resource's department
189	        $isBlacklisted = \App\Models\Blacklist::where('user_id', $user->id)
190	            ->where(function ($q) use ($resource) {
191	                $q->where(function ($inner) use ($resource) {
192	                    $inner->where('scope_type', 'department')
193	                          ->where('scope_id', $resource->department_id);
194	                })->orWhere(function ($inner) {
195	                    $inner->where('scope_type', 'global');
196	                });
197	            })
198	            ->where(function ($q) {
199	                $q->whereNull('expires_at')->orWhere('expires_at', '>', now());
200	            })
201	            ->exists();
202	
203	        if ($isBlacklisted) {
204	            return ['allowed' => false, 'reason' => 'You are restricted from accessing resources in this department.'];
205	        }
206	
207	        // Check if user is on the allowlist (if allowlist entries exist for this scope, user must be on it)
208	        $hasAllowlist = \App\Models\Allowlist::where('scope_type', 'department')
209	            ->where('scope_id', $resource->department_id)
210	            ->exists();
211	
212	        if ($hasAllowlist) {
213	            $isAllowed = \App\Models\Allowlist::where('user_id', $user->id)
214	                ->where('scope_type', 'department')
215	                ->where('scope_id', $resource->department_id)
216	                ->exists();
217	
218	            if (!$isAllowed) {
219	                return ['allowed' => false, 'reason' => 'You are not on the allowlist for this department.'];
220	            }
221	        }
222	
223	        return ['allowed' => true];
224	    }
225	}
