35	import { ref, onMounted } from 'vue';
36	import api from '../../services/api.js';
37	import ConflictBanner from '../../components/ConflictBanner.vue';
38	const entries = ref([]);
39	const error = ref('');
40	const saving = ref(false);
41	const loading = ref(true);
42	const removing = ref(null);
43	const form = ref({ user_id: '', scope_type: 'department', scope_id: '', reason: '', expires_at: '' });
44	
45	const fetchEntries = async () => {
46	  loading.value = true;
47	  try {
48	    const { data } = await api.get('/admin/blacklists');
49	    entries.value = data.data || data;
50	  } catch {} finally { loading.value = false; }
51	};
52	
53	onMounted(fetchEntries);
54	
55	const addEntry = async () => {
56	  saving.value = true; error.value = '';
57	  try {
58	    const key = 'black-' + Date.now();
59	    await api.post('/admin/blacklists', form.value, { headers: { 'X-Idempotency-Key': key } });
60	    form.value = { user_id: '', scope_type: 'department', scope_id: '', reason: '', expires_at: '' };
61	    await fetchEntries();
62	  } catch (e) { error.value = e.response?.data?.error || e.response?.data?.message || 'Failed.'; }
63	  finally { saving.value = false; }
64	};
65	
66	const removeEntry = async (id) => {
67	  removing.value = id;
68	  try {
69	    await api.delete(`/admin/blacklists/${id}`, { headers: { 'X-Idempotency-Key': 'del-black-' + id + '-' + Date.now() } });
70	    await fetchEntries();
71	  } catch (e) { error.value = e.response?.data?.error || e.response?.data?.message || 'Failed to remove.'; }
72	  finally { removing.value = null; }
73	};
