147	<script setup>
148	import { ref, onMounted, computed } from 'vue';
149	import api from '../../services/api.js';
150	import ConflictBanner from '../../components/ConflictBanner.vue';
151	
152	const activeTab = ref('remediation');
153	const loading = ref(true);
154	const error = ref('');
155	const remediationItems = ref([]);
156	const duplicates = ref([]);
157	const dataStats = ref(null);
158	const fixLoading = ref(null);
159	const dismissLoading = ref(null);
160	const mergeLoading = ref(null);
161	
162	const tabs = computed(() => [
163	  { id: 'remediation', label: 'Remediation Queue', count: remediationItems.value.length },
164	  { id: 'duplicates', label: 'Duplicate Candidates', count: duplicates.value.length },
165	  { id: 'stats', label: 'Statistics', count: 0 },
166	]);
167	
168	const severityClass = (s) => {
169	  const m = { critical: 'badge-red', high: 'badge-red', medium: 'badge-amber', low: 'badge-slate', info: 'badge-blue' };
170	  return m[s] || 'badge-slate';
171	};
172	
173	const loadTab = async () => {
174	  loading.value = true;
175	  error.value = '';
176	  try {
177	    if (activeTab.value === 'remediation') {
178	      const { data } = await api.get('/data-quality/remediation');
179	      remediationItems.value = data.data || data;
180	    } else if (activeTab.value === 'duplicates') {
181	      const { data } = await api.get('/data-quality/duplicates');
182	      duplicates.value = data.data || data;
183	    } else if (activeTab.value === 'stats') {
184	      const { data } = await api.get('/data-quality/stats');
185	      dataStats.value = data;
186	    }
187	  } catch (e) {
188	    error.value = e.response?.data?.message || 'Failed to load data.';
189	  } finally {
190	    loading.value = false;
191	  }
192	};
193	
194	const autoFix = async (id) => {
195	  fixLoading.value = id;
196	  try {
197	    await api.post(`/data-quality/remediation/${id}`, { action: 'remediate' }, { headers: { 'X-Idempotency-Key': 'fix-' + id + '-' + Date.now() } });
198	    remediationItems.value = remediationItems.value.filter(i => i.id !== id);
199	  } catch (e) {
200	    error.value = e.response?.data?.message || 'Auto-fix failed.';
201	  } finally {
202	    fixLoading.value = null;
203	  }
204	};
205	
206	const dismissItem = async (id) => {
207	  dismissLoading.value = id;
208	  try {
209	    await api.post(`/data-quality/remediation/${id}`, { action: 'skip' }, { headers: { 'X-Idempotency-Key': 'dismiss-' + id + '-' + Date.now() } });
210	    remediationItems.value = remediationItems.value.filter(i => i.id !== id);
211	  } catch (e) {
212	    error.value = e.response?.data?.message || 'Failed to dismiss.';
213	  } finally {
214	    dismissLoading.value = null;
215	  }
216	};
217	
218	const mergeDuplicates = async (group) => {
219	  mergeLoading.value = group.id;
220	  try {
221	    await api.post(`/data-quality/duplicates/${group.id}`, { action: 'confirmed' }, { headers: { 'X-Idempotency-Key': 'merge-' + group.id + '-' + Date.now() } });
222	    duplicates.value = duplicates.value.filter(d => d.id !== group.id);
223	  } catch (e) {
224	    error.value = e.response?.data?.message || 'Merge failed.';
225	  } finally {
226	    mergeLoading.value = null;
227	  }
228	};
229	
230	const dismissDuplicate = async (id) => {
231	  try {
232	    await api.post(`/data-quality/duplicates/${id}`, { action: 'dismissed' }, { headers: { 'X-Idempotency-Key': 'dismiss-dup-' + id + '-' + Date.now() } });
233	    duplicates.value = duplicates.value.filter(d => d.id !== id);
234	  } catch (e) {
235	    error.value = e.response?.data?.message || 'Failed to dismiss.';
236	  }
237	};
238	
239	onMounted(() => loadTab());
240	</script>
