23	            'location' => 'Building A', 'building' => 'A', 'floor' => '1',
24	        ]);
25	        $slot1 = VenueTimeSlot::create([
26	            'venue_id' => $venue->id, 'date' => now()->addDays(1)->format('Y-m-d'),
27	            'start_time' => '09:00:00', 'end_time' => '11:00:00', 'is_available' => true,
28	        ]);
29	        $slot2 = VenueTimeSlot::create([
30	            'venue_id' => $venue->id, 'date' => now()->addDays(1)->format('Y-m-d'),
31	            'start_time' => '14:00:00', 'end_time' => '16:00:00', 'is_available' => true,
32	        ]);
33	        return compact('resource', 'venue', 'slot1', 'slot2');
34	    }
