36	    public function test_create_venue_reservation_with_time_slot(): void
37	    {
38	        $student = $this->createStudent();
39	        ['resource' => $resource, 'venue' => $venue, 'slot1' => $slot] = $this->createVenueWithSlots();
40	
41	        $response = $this->actingAs($student)->postJson('/api/reservations', [
42	            'resource_id' => $resource->id,
43	            'reservation_type' => 'venue',
44	            'venue_id' => $venue->id,
45	            'venue_time_slot_id' => $slot->id,
46	            'idempotency_key' => 'venue-res-1',
47	        ], ['X-Idempotency-Key' => 'venue-res-1']);
48	
49	        $response->assertCreated();
50	        // Slot should be marked as occupied
51	        $this->assertNotNull($slot->fresh()->reserved_by_reservation_id);
52	    }
