81	            'idempotency_key' => 'double-1',
82	        ], ['X-Idempotency-Key' => 'double-1'])->assertCreated();
83	
84	        // Second student tries same slot
85	        $response = $this->actingAs($s2)->postJson('/api/reservations', [
86	            'resource_id' => $resource->id,
87	            'reservation_type' => 'venue',
