9	use Illuminate\Database\Eloquent\Relations\MorphOne;
10	
11	class LoanRequest extends Model
12	{
13	    protected $fillable = [
14	        'user_id',
15	        'resource_id',
16	        'inventory_lot_id',
17	        'quantity',
18	        'status',
19	        'requested_at',
20	        'due_date',
21	        'notes',
22	        'idempotency_key',
23	        'class_id',
24	        'assignment_id',
25	    ];
26	
27	    protected function casts(): array
28	    {
29	        return [
30	            'requested_at' => 'datetime',
31	            'due_date'     => 'datetime',
32	        ];
33	    }
34	
35	    // -------------------------------------------------------------------------
36	    // Relations
37	    // -------------------------------------------------------------------------
38	
39	    public function user(): BelongsTo
40	    {
41	        return $this->belongsTo(User::class);
42	    }
43	
44	    public function resource(): BelongsTo
45	    {
46	        return $this->belongsTo(Resource::class);
47	    }
48	
49	    public function inventoryLot(): BelongsTo
50	    {
51	        return $this->belongsTo(InventoryLot::class);
52	    }
53	
54	    public function classModel(): BelongsTo
55	    {
56	        return $this->belongsTo(ClassModel::class, 'class_id');
57	    }
58	
59	    public function assignment(): BelongsTo
60	    {
61	        return $this->belongsTo(Assignment::class);
62	    }
63	
64	    public function approval(): MorphOne
65	    {
66	        return $this->morphOne(Approval::class, 'approvable');
67	    }
68	
69	    public function checkout(): HasOne
70	    {
71	        return $this->hasOne(Checkout::class);
72	    }
73	
74	    // -------------------------------------------------------------------------
75	    // Scopes
76	    // -------------------------------------------------------------------------
77	
78	    public function scopePending(Builder $query): Builder
79	    {
80	        return $query->where('status', 'pending');
81	    }
82	
83	    public function scopeApproved(Builder $query): Builder
84	    {
85	        return $query->where('status', 'approved');
86	    }
87	
88	    public function scopeActive(Builder $query): Builder
89	    {
90	        return $query->whereIn('status', ['approved', 'checked_out']);
91	    }
92	
93	    public function scopeOverdue(Builder $query): Builder
94	    {
95	        return $query->where('status', 'checked_out')
96	            ->where('due_date', '<', now());
